'use strict';

// Loaded ONLY as the forked child's entry (mirrors jest-worker's processChild.js) --
// the parent resolves this path via require.resolve but never loads it in-process.
const { hello } = require('../types');

// STASIS_TEST_HOLD_HANDLE simulates a worker whose event loop never drains after the END
// message (a ref'd interval, a watcher some transformer left behind): the parent then
// force-kills it by SIGTERM after FORCE_EXIT_DELAY, exactly like jest-worker's
// forceExit. beforeExit/exit hooks never fire on a signal death -- the loader's
// SIGTERM shard flush is the only thing that saves this worker's capture.
if (process.env.STASIS_TEST_HOLD_HANDLE) setInterval(() => {}, 1 << 30);

const messageListener = (msg) => {
  if (msg[0] === 'call') {
    // Lazy, child-only load (mirrors processChild's dynamic require of the module it
    // was initialized with): workerDep is observed by NO process but this worker.
    const { transform } = require('../workerDep');
    process.send(['ok', transform(msg[1], hello)]);
  } else if (msg[0] === 'end') {
    // jest-worker's exitProcess(): drop the listener + unref the IPC channel so the
    // event loop drains and the process exits gracefully (beforeExit/exit hooks run).
    process.removeListener('message', messageListener);
    if (process.channel) process.channel.unref();
  }
};
process.on('message', messageListener);
